class Solution {
public:
    vector<int> findAllPeople(int n, vector<vector<int>>& meetings, int firstPerson) {
        // Initialize a union-find data structure
        vector<int> parent(n);
        for (int i = 0; i < n; ++i) {
            parent[i] = i;
        }

        // Function to find the root of a group
        function<int(int)> find = [&](int x) {
            if (parent[x] != x) {
                parent[x] = find(parent[x]);
            }
            return parent[x];
        };

        // Function to union two groups
        auto unionGroups = [&](int x, int y) {
            int rootX = find(x);
            int rootY = find(y);
            if (rootX != rootY) {
                parent[rootX] = rootY;
            }
        };

        // Initially, person 0 and firstPerson are in the same group
        unionGroups(0, firstPerson);

        // Sort meetings by time
        sort(meetings.begin(), meetings.end(), [](const auto& a, const auto& b) {
            return a[2] < b[2];
        });

        int currentTime = -1;
        vector<int> peopleWithSecret;

        // Process meetings
        for (const auto& meeting : meetings) {
            int x = meeting[0], y = meeting[1], time = meeting[2];

            if (time != currentTime) {
                // For each time frame, update people with secret
                for (int person : peopleWithSecret) {
                    unionGroups(person, find(person));
                }
                currentTime = time;
            }

            // Union the two people in the meeting
            unionGroups(x, y);
        }

        // Find all people with the secret
        for (int i = 0; i < n; ++i) {
            if (find(i) == find(0)) {
                peopleWithSecret.push_back(i);
            }
        }

        return peopleWithSecret;
    }
};
```
